example:
```python
from langchain_openai import ChatOpenAI
from langchain_core.tools import tool
from langchain.agents import create_tool_calling_agent, AgentExecutor
from langchain_core.prompts import ChatPromptTemplate

# Define custom tools with clear descriptions
@tool
def calculate(expression: str) -> str:
    """Evaluate a mathematical expression. Use for any math calculations."""
    try:
        return str(eval(expression))
    except Exception as e:
        return f"Error: {e}"

@tool
def get_word_count(text: str) -> int:
    """Count the number of words in a given text."""
    return len(text.split())

# Create agent with tools
llm = ChatOpenAI(model="gpt-4o-mini")
tools = [calculate, get_word_count]

prompt = ChatPromptTemplate.from_messages([
    ("system", "You are a helpful assistant with access to tools."),
    ("human", "{input}"),
    ("placeholder", "{agent_scratchpad}")
])

agent = create_tool_calling_agent(llm, tools, prompt)
executor = AgentExecutor(agent=agent, tools=tools, verbose=True)

result = executor.invoke({
    "input": "What is 15% of 847? Also, how many words are in: 'The quick brown fox jumps'"
})
print(result["output"])
```
